import React from 'react';
import { Link } from 'react-router-dom';
import './Benefits.css';

const benefits = [
  {
    title: '24/7 Email Support',
    desc: 'Need assistance? Our team is always available to ensure a smooth and hassle-free experience. 24 hours response time.',
  },
  {
    title: 'Proven Expertise',
    desc: "We've helped multiple brands and businesses create stunning, high-impact designs that drive results.",
  },
  {
    title: 'Seamless Collaboration',
    desc: 'We work closely with you, keeping communication transparent and revisions efficient to bring your vision to life.',
  },
  {
    title: 'Future-Ready Solutions',
    desc: 'Our designs grow with your brand, ensuring long-term success and adaptability.',
  },
];

const clientLogos = [
  'https://framerusercontent.com/images/lBk7MKclfzJRlatPc13MvYtptk.svg',
  'https://framerusercontent.com/images/OHfziRjK2HdoOgrAXlPXc55VYQ.svg',
  'https://framerusercontent.com/images/C8vnHs7e8IbLZooep0gNip6eylU.svg',
  'https://framerusercontent.com/images/KNj9BRJvdrtCaYx5m7um7EmT8.svg',
  'https://framerusercontent.com/images/8wpt2H14XHcb4yoW182iK0MGxs.svg',
  'https://framerusercontent.com/images/jqmWIOA4WlrHoWQKgzTtrOgybg.svg',
  'https://framerusercontent.com/images/qNMZaMQpAKdhOYxA9xp6LSCc54.svg',
];

const moodImages = [
  'https://framerusercontent.com/images/sN7Mx50XSfe6J39ZUtPdjuLNNn0.png',
  'https://framerusercontent.com/images/xUErU0PTiBzDMhy1RZwdDq8qGc.png',
  'https://framerusercontent.com/images/7A7ccBOL3ZFQLk22oYa259X4NU.jpg',
  'https://framerusercontent.com/images/IJ9cgCSRZl2bnYNQHbnKMtf3T0.png',
];

export default function Benefits() {
  return (
    <section className="benefits">
      <div className="container">
        <div className="benefits-header">
          <div>
            <p className="section-label">Benefits</p>
            <h2 className="benefits-heading">Why Choose Scarlet?</h2>
            <p className="benefits-sub">
              We specialize in creating bold, high-impact digital experiences that set brands apart.
            </p>
          </div>
          <Link to="/contact" className="btn-primary">Let's talk</Link>
        </div>

        {/* Top row: creativity + features */}
        <div className="benefits-top">
          <div className="benefit-feature-card big-card">
            <span className="big-card-label">Cutting-Edge Creativity</span>
            <img
              src="https://framerusercontent.com/images/WmLWb5sGkbaG2hNrdhMigvNPYo.png"
              alt="Creativity"
              className="big-card-img"
            />
          </div>
          <div className="benefits-features">
            {benefits.map((b) => (
              <div key={b.title} className="benefit-card">
                <div className="benefit-check">✓</div>
                <div>
                  <h4 className="benefit-title">{b.title}</h4>
                  <p className="benefit-desc">{b.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* Mood images row */}
        <div className="mood-grid">
          {moodImages.map((img, i) => (
            <div key={i} className="mood-item">
              <img src={img} alt={`Design work ${i + 1}`} />
            </div>
          ))}
          <div className="mood-stat">
            <span className="mood-number">200+</span>
            <span className="mood-label">Satisfied Clients</span>
          </div>
        </div>

        {/* Client logos */}
        <div className="clients-strip">
          <div className="logos-track">
            {[...clientLogos, ...clientLogos].map((logo, i) => (
              <div key={i} className="logo-item">
                <img src={logo} alt={`Client ${i + 1}`} />
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
